+        } else if (limit > 1) {
+            outputOp = String.format("output selection with MS=%d", limit);
+            partRange = String.format("in [0..%d]", limit-1);
+        } else {
+            outputOp = "output in-place (MO=MS=1)";
+            partRange = "0";
